const cheerio = require('cheerio');
const html = $input.item.json;
const $ = cheerio.load(html);

const jobs = [];

$('.freelancer-card, .mission-card').each((i, el) => {
  const $el = $(el);
  const title = $el.find('.mission-title, h3').text().trim();
  const company = $el.find('.company-name, .client-name').text().trim();
  const location = $el.find('.location').text().trim() || 'Remote';
  const description = $el.find('.mission-description, .description').text().trim();
  const url = 'https://www.malt.fr' + $el.find('a').attr('href');
  const rate = $el.find('.rate, .tjm').text().trim();

  if (title && url) {
    jobs.push({
      title,
      company: company || 'Client Malt',
      location,
      raw_description: description,
      url,
      rate,
      source: 'Malt',
      scraping_source: 'malt',
      scraped_at: new Date().toISOString()
    });
  }
});

console.log('✅ [Malt] Jobs extraits:', jobs.length);
return jobs.map(j => ({ json: j }));

